      owner_id: "coder",
      agents_dir: ".runtime/agents",
    });

    expect(
      prompts.map((prompt) => ({
        id: prompt.id,
        role: prompt.role,
        priority: prompt.priority,
        source: prompt.source,
        title: prompt.title,
